VALUES
  ('social-worker-moex-08030', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依現行兒童及少年福利法之規定，社會工作人員在兒童及少年保護上，主要扮演下列何種專業職責？', '["在兒童及少年有遭受重大危險傷害威脅時，社會工作人員應立即向主管機關通報並協助調查，至遲不 得超過24小時", "安置期間，兒童及少年接受訪談、偵訊、訊問或身體檢查，應由社會工作人員陪同，並保護其隱私", "社會工作人員對於安置期間期滿，兒童及少年返回其家庭後，應續予追蹤輔導一年", "為確保兒童及少年最佳利益，必要時社會工作人員得代覓寄養家庭"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08031', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在身心障礙者權益保障法中，明文規定社會工作人員的角色有三，下列敘述何者正確？', '["參與有關身心障礙者身分之專業鑑定及評估；當身心障礙者受到不當對待危害時負有通報責任；刑事 被告或犯罪嫌疑人因智能障礙無法為完全之陳述時，得擔任輔佐人", "當身心障礙者受到不當對待危害時負有通報責任；刑事被告或犯罪嫌疑人因身心障礙無法為完全之陳 述時，得擔任輔佐人；當身心障礙者必須接受訪談、偵訊、訊問或身體檢查，陪同之並保護其隱私", "參與有關身心障礙者身分之專業鑑定及評估；當身心障礙者受到不當對待危害時負有通報及協助調查 之責任；刑事被告或犯罪嫌疑人因身心障礙無法為完全之陳述時，得擔任輔佐人", "參與有關身心障礙者身分之專業鑑定及評估；當身心障礙者受到不當對待危害時負有通報及協助調查 之責任；當身心障礙者必須接受訪談、偵訊、訊問或身體檢查，陪同之並保護其隱私"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08032', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國69年，我國通過社會福利三法。請問，該年通過的是那三個法案？', '["身心障礙者保護法、社會救助法、兒童福利法", "殘障福利法、社會救助法、兒童福利法", "殘障福利法、社會救助法、老人福利法", "兒童福利法、少年福利法、老人福利法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08033', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不屬於民國93年社會福利政策綱領之制定原則？', '["包容弱勢國民", "投資積極福利", "整合服務資源", "因應全球變遷"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08034', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '晚近我國社會救助法朝明定及限縮「家庭人口之計算範圍」之方向修法，其主要用意大致較接近下列何 者？', '["避免福利依賴之類的道德風險發生", "反應社會變遷需求", "防範救助資源重複浪費", "便於計算家庭總收入"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08035', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據家庭暴力防治法，保護令除下列何種保護令外，應於核發後24小時內發送當事人、被害人、警察機 關及直轄市、縣（市）主管機關？', '["臨時保護令", "緊急保護令", "通常保護令", "暫時保護令"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08036', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據社會工作師法，社會工作師及專科社會工作師執業，應接受繼續教育，並多久提出完成繼續教育證 明文件，辦理執業執照更新？', '["每三年", "每四年", "每六年", "每八年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08037', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者並非公益勸募條例所稱之勸募團體？', '["各級學校", "行政法人", "公益性社團法人", "財團法人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08038', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國對於原住民福利服務的相關立法並不多，請問「政府應積極辦理原住民族社會福利事項，規劃建立 原住民族社會安全體系，並特別保障原住民兒童、老人、婦女及身心障礙者之相關權益。」之規定，係 出自那個法案？', '["社會福利基本法", "原住民福利基本法", "原住民族基本法", "原住民族基本權益保障法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08039', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關「特殊境遇家庭扶助條例」的敘述，何者不正確？', '["「特殊境遇家庭扶助條例」的前身，原名稱為「特殊境遇婦女扶助條例」", "特殊境遇家庭申請緊急生活扶助，應於事實發生後六個月內，檢具戶口名簿影本及其他相關證明文件，向 戶籍所在地直轄市、縣（市）主管機關提出申請，或由鄉（鎮、市、區）公所、社會福利機構轉介申請", "特殊境遇家庭符合規定申請緊急生活扶助者，按當年度低收入戶每人每月最低生活費用標準一倍核發， 每人每次以補助3個月為原則，同一個案同一事由以補助一次為限", "特殊境遇家庭符合規定，並有15歲以下子女或孫子女者，得申請子女生活津貼。子女生活津貼之核發 標準，每一名子女或孫子女每月補助當年度最低工資之十分之一，每年申請一次"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
